305	static int getArgs(int argc, char* argv[])
306	{
307	    bool b_help = false;
308	    int i = 1;
309	    while(true)
310	    {
311	        if (i >= argc) break;
312	        const char* arg = argv[i];    
313	        
314	        if (strcmp(arg, "-h") == 0) { b_help = true; break; }
315	        else if (strcmp(arg, "--help") == 0) { b_help = true; break; }
316	        else if (strcmp(arg, "--bin") == 0) 
317	        { 
318	            if (i+1 >= argc) { break; }
319	            appargs.path_bin = string(argv[++i]);
320	        }
321	        else if (strcmp(arg, "--input") == 0) 
322	        { 
323	            if (i+1 >= argc) { break; }
324	            appargs.path_input = string(argv[++i]);
325	        }
326	        else if (strcmp(arg, "--pack_shape") == 0)
327	        {
328	            if (i+1 >= argc) { break; }
329	            sscanf(argv[++i], "%d,%d,%d", &appargs.pack_output_c, &appargs.pack_output_h, &appargs.pack_output_w);
330	        }
331	        else if (strcmp(arg, "--interface") == 0) 
332	        { 
333	            if (i+1 >= argc) { break; }
334	            appargs.interface = atoi(argv[++i]);
335	        }
336	        else if (strcmp(arg, "--txt_col") == 0) 
337	        { 
338	            if (i+1 >= argc) { break; }
339	            appargs.txt_col = atoi(argv[++i]);
340	            if (appargs.txt_col < 0) appargs.txt_col = 4;
341	        }
342	        else { b_help = true; break; }
343	        i++;
344	    }
345	    if (b_help) { usage(argv[0]); return -1; }
346	    
347	    return 0;
348	}
