395	template <typename T>
396	static void process_mean_norm(float* pdst, void* src, int c, int h, int w, vector<float>& mean, vector<float>& norm)
397	{
398	    T* psrc = (T*)src;
399	    int hw = h*w;
400	    for (int k = 0; k < c; k++)    // channel
401	    {
402	        float* pd = (float*)pdst + k*hw;
403	        T* ps = (T*)psrc + k*hw;
404	        for (int j = 0; j < hw; j++) 
405	        {
406	            *pd++ = (*ps++ - mean[k]) * norm[k];
407	        }
408	    }
409	}
