432	static int eeptpu_write_input(int input_id, string path_input, NET_INPUT_INFO* input_info)
433	{
434	    int ret = 0;
435	    
436	    printf("InputID[%d]: %s\n", input_id, (char*)path_input.c_str());
437	
438	    std::string ext = path_input.substr(path_input.find_last_of(".") + 1);
439	    transform(ext.begin(), ext.end(), ext.begin(), ::tolower);
440	    
441	    if (ext == "npy")
442	    {
443	        printf("Use npy input\n");
444	        void* src_data = NULL;
445	        int shp[4] = {1,0,0,0}; // shape[0] always be 1.   b,c,h,w
446	        int data_type;
447	        ret = read_npy(path_input, &src_data, &(shp[1]), &(shp[2]), &(shp[3]), &data_type);
448	        if (ret < 0)
449	        {
450	            printf("npy data(%s) read fail.\n", path_input.c_str());
451	            return ret;
452	        }
453	        //printf("Read npy ok, shape:%d,%d,%d, data_type:%d\n", shp[1], shp[2], shp[3], data_type);
454	        
455	#if 1
456	        int srclen = shp[1] * shp[2] * shp[3];
457	        switch(data_type)
458	        {
459	            case 1: input_save_txt<float>(input_id, src_data, srclen, "%f,"); break;  // fp32
460	            case 2: input_save_txt<short>(input_id, src_data, srclen, "%f,"); break;  // fp16
461	            case 3: input_save_txt<signed char>(input_id, src_data, srclen, "%d,"); break;  // char
462	            case 4: input_save_txt<short>(input_id, src_data, srclen, "%d,"); break;  // short
463	            case 5: input_save_txt<int>(input_id, src_data, srclen, "%d,"); break;  // int
464	            case 7: input_save_txt<unsigned char>(input_id, src_data, srclen, "%d,"); break;  // uchar
465	            default : break;
466	        }
467	#endif
468	        
469	        void* in_data = src_data;
470	        bool b_in_data_need_free = false;
471	
472	        // check network's mean/norm setting.
473	        vector<float> net_mean; vector<float> net_norm;
474	        tpu->eeptpu_get_mean_norm(net_mean, net_norm);
475	        if ( (is_vector_all_value<float>(net_mean, 0.0) == false) || (is_vector_all_value<float>(net_norm, 1.0) == false) )
476	        {
477	            printf("Warning: Input is npy file, and found 'mean,norm' in this network. \n");
478	            printf("         Make sure the input npy data is processed 'mean&norm'!\n");
479	            printf("         Mean: "); print_mean_norm<float>(net_mean, 0.0); printf("\n");
480	            printf("         Norm: "); print_mean_norm<float>(net_norm, 1.0); printf("\n");
481	            if (1)
482	            {
483	                vector<float> use_mean; vector<float> use_norm;
484	                use_mean.assign(net_mean.begin(), net_mean.end());
485	                use_norm.assign(net_norm.begin(), net_norm.end());
486	                if ( (int)use_mean.size() < shp[1] )    // maybe use 'del_last_channels' mode.
487	                {
488	                    int cnt = shp[1] - use_mean.size();
489	                    for (int k = 0; k < cnt; k++) 
490	                    {
491	                        use_mean.push_back(0.0);
492	                        use_norm.push_back(1.0);
493	                    }
494	                }
495	
496	                in_data = (float*)malloc(shp[1]*shp[2]*shp[3]*sizeof(float));
497	                b_in_data_need_free = true;
498	                switch(data_type)
499	                {
500	                    case 1: process_mean_norm<float>((float*)in_data, src_data, shp[1], shp[2], shp[3], use_mean, use_norm); break;  // fp32
501	                    case 2: process_mean_norm<short>((float*)in_data, src_data, shp[1], shp[2], shp[3], use_mean, use_norm); break;  // fp16
502	                    case 3: process_mean_norm<signed char>((float*)in_data, src_data, shp[1], shp[2], shp[3], use_mean, use_norm); break;  // char
503	                    case 4: process_mean_norm<short>((float*)in_data, src_data, shp[1], shp[2], shp[3], use_mean, use_norm); break;  // short
504	                    case 5: process_mean_norm<int>((float*)in_data, src_data, shp[1], shp[2], shp[3], use_mean, use_norm); break;  // int
505	                    case 7: process_mean_norm<unsigned char>((float*)in_data, src_data, shp[1], shp[2], shp[3], use_mean, use_norm); break;  // uchar
506	                    default : printf("Not supported data type.\n"); if (src_data != NULL) free(src_data); return -1; 
