682	        
683	        in_list.clear();
684	
685	        if(S_ISDIR(s_buf.st_mode))  
686	        {  
687	            if (file_path.c_str()[file_path.length()-1] != '/') {
688	                file_path +=  "/";
689	            }
690	
691	            int i=0;
692	            std::string absolute_path;
693	            std::string file_name;
694	            
695	            vector<struct st_input> items;
