275	        throw std::runtime_error("npz_load: Error! Unable to open file "+fname+"!");
276	    }
277	
278	    cnpy::npz_t arrays;  
279	
280	    while(1) {
281	        std::vector<char> local_header(30);
282	        size_t headerres = fread(&local_header[0],sizeof(char),30,fp);
283	        if(headerres != 30)
284	            throw std::runtime_error("npz_load: failed fread");
285	
286	        //if we've reached the global header, stop reading
287	        if(local_header[2] != 0x03 || local_header[3] != 0x04) break;
288	
289	        //read in the variable name
290	        uint16_t name_len = *(uint16_t*) &local_header[26];
291	        std::string varname(name_len,' ');
292	        size_t vname_res = fread(&varname[0],sizeof(char),name_len,fp);
293	        if(vname_res != name_len)
294	            throw std::runtime_error("npz_load: failed fread");
295	
296	        //erase the lagging .npy        
297	        varname.erase(varname.end()-4,varname.end());
298	
299	        //read in the extra field
300	        uint16_t extra_field_len = *(uint16_t*) &local_header[28];
301	        if(extra_field_len > 0) {
302	            std::vector<char> buff(extra_field_len);
303	            size_t efield_res = fread(&buff[0],sizeof(char),extra_field_len,fp);
304	            if(efield_res != extra_field_len)
305	                throw std::runtime_error("npz_load: failed fread");
306	        }
307	
308	        uint16_t compr_method = *reinterpret_cast<uint16_t*>(&local_header[0]+8);
309	        uint32_t compr_bytes = *reinterpret_cast<uint32_t*>(&local_header[0]+18);
310	        uint32_t uncompr_bytes = *reinterpret_cast<uint32_t*>(&local_header[0]+22);
311	
312	        if(compr_method == 0) {arrays[varname] = load_the_npy_file(fp);}
313	        else {arrays[varname] = load_the_npz_array(fp,compr_bytes,uncompr_bytes);}
314	    }
315	
316	    fclose(fp);
317	    return arrays;  
318	}
