330	
331	        //if we've reached the global header, stop reading
332	        if(local_header[2] != 0x03 || local_header[3] != 0x04) break;
333	
334	        //read in the variable name
335	        uint16_t name_len = *(uint16_t*) &local_header[26];
336	        std::string vname(name_len,' ');
337	        size_t vname_res = fread(&vname[0],sizeof(char),name_len,fp);      
